#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-06

# i18n alignment: render box pattern with CJK + Devanagari labels and
# verify column alignment via python3 wcwidth.
# Validates that CC 2.1.116's CJK alignment fix actually holds in our
# rendering and that authors can paste non-Latin labels safely.

set -euo pipefail

ROOT="$(cd "$(dirname "$0")/../.." && pwd)"
RENDER="$ROOT/scripts/render-ascii.sh"
LABELS="$ROOT/tests/fixtures/ascii/i18n/labels.json"

[ -x "$RENDER" ] || { echo "✗ render-ascii.sh not executable"; exit 1; }
[ -f "$LABELS" ] || { echo "✗ labels fixture missing: $LABELS"; exit 1; }

# wcwidth via python3 stdlib (unicodedata.east_asian_width).
if ! command -v python3 >/dev/null 2>&1; then
  echo "⚠ python3 not available — skipping i18n alignment test"
  exit 0
fi

WIDTH=40
fail=0

# Iterate labels via python (jq alternative, since labels.json may not be flat array).
labels_for() {
  python3 -c "
import json,sys
labels=json.load(open('$LABELS'))
for l in labels.get(sys.argv[1], []):
    print(l)
" "$1"
}

check_alignment() {
  local script="$1" label="$2"
  local out width_first width_last
  out=$("$RENDER" box --set default --width "$WIDTH" --label "$label")
  width_first=$(printf '%s' "$out" | head -1 | python3 -c '
import sys, unicodedata
line = sys.stdin.read().rstrip("\n")
def w(s):
    n = 0
    for c in s:
        n += 2 if unicodedata.east_asian_width(c) in ("W","F") else 1
    return n
print(w(line))
')
  width_last=$(printf '%s' "$out" | tail -1 | python3 -c '
import sys, unicodedata
line = sys.stdin.read().rstrip("\n")
def w(s):
    n = 0
    for c in s:
        n += 2 if unicodedata.east_asian_width(c) in ("W","F") else 1
    return n
print(w(line))
')
  if [ "$width_first" = "$width_last" ]; then
    printf '  ✓ %s/%s aligned (width %s)\n' "$script" "$label" "$width_first"
  else
    printf '  ✗ %s/%s drift: top=%s bottom=%s\n' "$script" "$label" "$width_first" "$width_last"
    fail=$((fail + 1))
  fi
}

for script in japanese chinese devanagari; do
  printf '\n— %s —\n' "$script"
  while IFS= read -r label; do
    [ -z "$label" ] && continue
    check_alignment "$script" "$label"
  done <<EOF
$(labels_for "$script")
EOF
done

printf '\n✓ i18n: %s\n' "$([ "$fail" -eq 0 ] && echo PASS || echo "$fail FAIL")"
[ "$fail" -eq 0 ] || exit 1
